import{_ as a,o as e,c as s,a2 as c}from"./chunks/framework.N6Nd-M9-.js";const h=JSON.parse('{"title":"卷首语","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/组长手册/00-卷首语.md","filePath":"notes/企业文化/组长手册/00-卷首语.md"}'),l={name:"notes/企业文化/组长手册/00-卷首语.md"};function i(n,t,r,o,d,p){return e(),s("div",null,[...t[0]||(t[0]=[c('<h1 id="卷首语" tabindex="-1">卷首语 <a class="header-anchor" href="#卷首语" aria-label="Permalink to &quot;卷首语&quot;">​</a></h1><div class="tc-gradient tc-gradient-blue-green"><p style="margin:0 0 15px 0;font-size:16px;line-height:1.8;" class="tc-body"> 亲爱的小伙伴： </p><p style="margin:0 0 15px 0;font-size:16px;line-height:1.8;" class="tc-body"> 感谢你与同创主悦携手同行！ </p><p style="margin:0 0 20px 0;font-size:15px;line-height:1.8;" class="tc-body"> 恭喜你脱去新手的标签，达到组长的标准，真正开始触摸平台的机会，顺利来到你在同创主悦璀璨职业生涯的第二篇章！让我们一起 <strong class="tc-blue">Juice</strong> 一下！ </p></div><hr><h2 id="组长的角色定位" tabindex="-1">组长的角色定位 <a class="header-anchor" href="#组长的角色定位" aria-label="Permalink to &quot;组长的角色定位&quot;">​</a></h2><div class="tc-grid tc-grid-auto" style="gap:15px;margin:20px 0;"><div class="tc-card tc-card-blue"><p style="margin:0 0 12px 0;" class="tc-title tc-blue">⭐ 榜样</p><p style="margin:0;font-size:14px;line-height:1.7;" class="tc-body"> 组长是队员最近距离接触到的榜样。成为组长，是对你态度、作业技巧、责任心、学习与教育能力的初步肯定。 </p></div><div class="tc-card tc-card-green"><p style="margin:0 0 12px 0;" class="tc-title tc-green">📊 管理员</p><p style="margin:0;font-size:14px;line-height:1.7;" class="tc-body"> 作为基层的管理员，直接负责达成工作区域内的利润指标。 </p></div><div class="tc-card tc-card-orange"><p style="margin:0 0 12px 0;" class="tc-title tc-orange">🔗 传播窗口</p><p style="margin:0;font-size:14px;line-height:1.7;" class="tc-body"> 直接链接企业机会与新人，是连接公司与新人的桥梁。 </p></div><div class="tc-card tc-card-red"><p style="margin:0 0 12px 0;" class="tc-title tc-red">👨‍🏫 启蒙老师</p><p style="margin:0;font-size:14px;line-height:1.7;" class="tc-body"> 直接指导与评价队员的作业过程，是队员成长的第一任导师。 </p></div></div><hr><h2 id="组长的核心工作" tabindex="-1">组长的核心工作 <a class="header-anchor" href="#组长的核心工作" aria-label="Permalink to &quot;组长的核心工作&quot;">​</a></h2><div class="tc-container tc-container-blue"><p style="margin:0 0 20px 0;" class="tc-bold tc-blue">🎯 主旋律</p><div class="tc-flex tc-flex-wrap"><span class="tc-tag tc-tag-blue">以身作则做好榜样</span><span class="tc-tag tc-tag-green">带人</span><span class="tc-tag tc-tag-orange">建队</span></div></div><hr><h2 id="成长价值" tabindex="-1">成长价值 <a class="header-anchor" href="#成长价值" aria-label="Permalink to &quot;成长价值&quot;">​</a></h2><div class="tc-gradient tc-gradient-blue-green"><blockquote style="margin:0 0 20px 0;" class="tc-quote tc-quote-blue tc-body tc-bold"> &quot;万丈高楼平地起&quot;——组长阶段是为管理之路夯实基础的最好机会。 </blockquote><p style="margin:0 0 15px 0;" class="tc-body">在带领新人与团队的过程中，你将具备进阶中级管理层的必备要素：</p><div class="tc-flex tc-flex-col" style="gap:10px;"><span class="tc-sub tc-body">✨ 见更多的人、丰富自己的阅历与眼界，拥有宠辱不惊的强悍心态</span><span class="tc-sub tc-body">✨ 持续磨练市场技巧并逐渐掌握学习与教育的能力，将优秀变成一种习惯</span><span class="tc-sub tc-body">✨ 通过建立属于自己的团队，拥有属于自己的人脉圈</span></div></div><hr><h2 id="展望未来" tabindex="-1">展望未来 <a class="header-anchor" href="#展望未来" aria-label="Permalink to &quot;展望未来&quot;">​</a></h2><div class="tc-gradient tc-gradient-red-orange tc-center"><p style="margin:0 0 20px 0;font-size:16px;line-height:1.8;" class="tc-body"> 同创主悦是条通往美好生活的道路，在短暂地停歇庆祝后，让我们带着新的责任与期望继续上路！ </p><p style="margin:0 0 20px 0;font-size:15px;line-height:1.8;" class="tc-body"> 接下来的征程也许不易，但也必然会收获更大的成就感！ </p><p style="margin:0;font-size:20px;" class="tc-bold tc-blue"> 让我们一起创造美好的生活，Juice！ </p></div>',14)])])}const b=a(l,[["render",i]]);export{h as __pageData,b as default};
